import{_ as s,o as i,c as t,a4 as a}from"./chunks/framework.CyI4nVbD.js";const k=JSON.parse('{"title":"Developing CifVis","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/index.md","filePath":"contributing/index.md"}'),n={name:"contributing/index.md"};function o(r,e,d,l,c,h){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="developing-cifvis" tabindex="-1">Developing CifVis <a class="header-anchor" href="#developing-cifvis" aria-label="Permalink to &quot;Developing CifVis&quot;">​</a></h1><p>Contributor guide: the lay of the land, how the layers depend on each other, and where to find the full API reference.</p><h2 id="the-lay-of-the-land" tabindex="-1">The lay of the land <a class="header-anchor" href="#the-lay-of-the-land" aria-label="Permalink to &quot;The lay of the land&quot;">​</a></h2><p>All source lives under <code>src/lib/</code>. Here&#39;s what&#39;s responsible for what:</p><ul><li><strong><code>read-cif/</code></strong> — <code>CIF</code>, <code>CifBlock</code>, <code>CifLoop</code>. Turns raw CIF text into a generic key/value + loop-table object model. Knows nothing about crystallography — no atoms, no cells, no symmetry. Depends on nothing else in the codebase.</li><li><strong><code>structure/</code></strong> — <code>CrystalStructure</code>, <code>UnitCell</code>, <code>Atom</code>, plus the supporting pieces (<code>bonds.js</code>, <code>cell-symmetry.js</code>, <code>adp.js</code>, <code>position.js</code>, <code>fract-to-cart.js</code>, <code>bond-classification.js</code>, <code>applied-symmetry.js</code>). The crystallographic domain model, built directly from a <code>CifBlock</code>. No DOM, no Three.js.</li><li><strong><code>structure/structure-modifiers/</code></strong> — the Filters (<code>HydrogenFilter</code>, <code>DisorderFilter</code>, <code>SymmetryGrower</code>, <code>AtomLabelFilter</code>, <code>BondGenerator</code>, <code>IsolatedHydrogenFixer</code>), all extending <code>BaseFilter</code>. Each transforms one <code>CrystalStructure</code> into another. Depends only on <code>structure/</code>.</li><li><strong><code>structure/structure-modifiers/growing/</code></strong> — the symmetry/fragment &quot;growing&quot; engine behind <code>SymmetryGrower</code>: <code>growCell</code>, <code>growFragment</code>, <code>growExternalHBonds</code>. Depends only on the parent <code>structure/</code> folder.</li><li><strong><code>density/</code></strong> — the reflection-to-map pipeline: FCF/custom coefficient parsing, observed-reflection merging and systematic-absence filtering, IAM/Cromer–Mann structure factors, anomalous-dispersion and extinction corrections, Fourier grids, progressive workers, Marching Cubes, and symmetry-aware mesh reuse. Its numerical core depends on <code>read-cif/</code> and <code>structure/</code>; only the surface modules depend on Three.js.</li><li><strong><code>ortep3d/</code></strong> — <code>ORTEP3JsStructure</code> (converts a <code>CrystalStructure</code> into Three.js geometry) and <code>CrystalViewer</code> (the orchestrator: CIF parsing → filters → ORTEP3D scene → camera/controls/lighting/selection/density). Along with the density surface modules, this is the rendering layer that imports Three.js. <code>CrystalViewer</code> joins the structure-modifier, repair, structure, and density pipelines.</li><li><strong><code>fix-cif/</code></strong> — <code>tryToFixCifBlock</code> — repairs malformed/nonstandard CIF blocks (reconciling atom labels, guessing missing symmetry operations) before they reach <code>CrystalStructure.fromCIF</code>. Depends only on <code>read-cif/</code>.</li><li><strong><code>generated/</code></strong> — <code>svg-icons.js</code> — auto-generated, gitignored, regenerated by <code>npm run generate-svg-icons</code> from <code>src/svg-icons/</code>. Required at runtime by <code>widget.js</code>.</li><li><strong><code>svg-icons/</code></strong> — hand-authored source SVGs, the input to the icon code-generation step.</li></ul><h2 id="hierarchy-of-objects" tabindex="-1">Hierarchy of objects <a class="header-anchor" href="#hierarchy-of-objects" aria-label="Permalink to &quot;Hierarchy of objects&quot;">​</a></h2><p>Each layer only imports from the ones below it, so a change to <code>read-cif/</code> can only ripple upward, never sideways or back down:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read-cif ─┬─► structure ──► structure-modifiers ──┐</span></span>
<span class="line"><span>           ├─► density ◄──────── structure ─────────┤</span></span>
<span class="line"><span>           └─► fix-cif ─────────────────────────────┴─► ortep3d ──► widget.js ──► index.js</span></span></code></pre></div><p><code>ortep3d/crystal-viewer.js</code> is the pipeline glue: it&#39;s the one file that imports from <code>structure</code>, <code>structure-modifiers</code>, <code>fix-cif</code>, <code>read-cif</code>, and <code>density</code> together to drive CIF parsing → filters → rendering end to end. When you change the public shape of any of those lower layers, check this file.</p><h3 id="two-entry-points" tabindex="-1">Two entry points <a class="header-anchor" href="#two-entry-points" aria-label="Permalink to &quot;Two entry points&quot;">​</a></h3><p><code>package.json</code>&#39;s <code>exports</code> map exposes two entry points:</p><table tabindex="0"><thead><tr><th>Entry</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cifvis</code> → <code>src/index.js</code></td><td>Browser entry. Exports everything, and registers <code>&lt;cifview-widget&gt;</code> as a custom element.</td></tr><tr><td><code>cifvis/nobrowser</code> → <code>src/index.nobrowser.js</code></td><td>Same core exports, including CIF/structure APIs, Filters, map calculation, IAM, anomalous lookup, and reflection readers, but <code>CrystalViewer</code>/<code>CifViewWidget</code> are stubs that throw — safe to import in Node/SSR/test environments with no <code>window</code>.</td></tr></tbody></table><p>The core (<code>read-cif</code>, <code>structure</code>, <code>structure-modifiers</code>, <code>fix-cif</code>, the numerical density modules, <code>ORTEP3JsStructure</code>, and <code>formatValueEsd</code>) is deliberately DOM-free by construction — only <code>CrystalViewer</code> (canvas/WebGL) and <code>CifViewWidget</code> (custom element) need a browser.</p><h2 id="the-playground" tabindex="-1">The playground <a class="header-anchor" href="#the-playground" aria-label="Permalink to &quot;The playground&quot;">​</a></h2><p>The playground under <code>site/</code> is deliberately kept readable as reference code for driving <code>CrystalViewer</code> directly. <code>site/src/main.js</code> is a thin, linear boot file (viewer lifecycle, file loading, toolbar wiring); <code>playground-cif-routing.js</code> classifies uploaded CIF/FCF/Cube files; <code>playground-settings.js</code> is the pure logic behind the settings overlay (it consumes the same generated options metadata as this documentation&#39;s reference tables); <code>settings-overlay.js</code> is its DOM layer.</p><h2 id="working-on-the-documentation" tabindex="-1">Working on the documentation <a class="header-anchor" href="#working-on-the-documentation" aria-label="Permalink to &quot;Working on the documentation&quot;">​</a></h2><p>The docs you are reading are a VitePress site under <code>docs/</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # live-reloading dev server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # production build to docs/.vitepress/dist</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gen:options</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # regenerate the options-reference tables from the source defaults</span></span></code></pre></div><p>The options-reference tables are generated by <code>scripts/gen-options-reference.mjs</code> from <code>structure-settings.js</code> and the <code>DEFAULT_*</code> density option objects; descriptions live in <code>docs/.vitepress/data/option-descriptions.js</code>. A test (<code>scripts/gen-options-reference.test.js</code>) fails when the committed tables drift from the code or a new option lacks a description — after adding an option, run <code>npm run gen:options</code> and add its description. Live demos in the docs import the library directly from <code>src/</code>, so they always reflect your working tree.</p><h2 id="performance-benchmarking" tabindex="-1">Performance benchmarking <a class="header-anchor" href="#performance-benchmarking" aria-label="Permalink to &quot;Performance benchmarking&quot;">​</a></h2><p><code>benchmark/speed.mjs</code> loads real CIF files against the built library in headless Chrome (via <code>playwright-core</code>) and reports parse/build time, render time, and WebGL draw-call count per structure — self-contained, no external server required.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path/to/structure.cif</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path/to/cif/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --limit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path/to/file-list.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> results.csv</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --render-mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> constant</span></span></code></pre></div><p>The target can be a single <code>.cif</code> file, a directory (searched recursively), or a text file listing one path per line (optionally <code>path&lt;TAB&gt;size</code>). It builds <code>dist/cifvis.alldeps.js</code> automatically if missing. Chrome&#39;s location is taken from <code>--chrome</code> or the <code>CHROME_PATH</code> environment variable if the system default isn&#39;t found.</p><p>Density work has four focused benchmarks:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench:iam</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> structure.cif</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench:density-symmetry</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> structure.cif</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reflections.fcf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench:density-cod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/cod/cif</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sample</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmark/density-pipeline-cod.csv</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench:density-fit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench:contours</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> structure.cif</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scalar-field.cube</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7</span></span></code></pre></div><p><code>bench:iam</code> separates model construction, first calculation, and warmed repeated calculation; when calculated F-squared values are present it also reports agreement. The symmetry benchmark alternates direct and symmetry-aware surface generation and reports wall-clock, polygonization, stitching, and Marching Cubes timings so ordering and JIT warm-up do not favour one path consistently. The contour benchmark reports plane setup, linear or monotone-tricubic sampling, multi-level Marching Squares extraction, transferable packing, and main-thread thick-line geometry independently. This mirrors the production worker/rendering boundary without including worker startup.</p><p><code>bench:density-cod</code> calibrates the full synthetic Fo−Fc path on a deterministic COD sample. HKL generation and artificial noisy Fobs creation are deliberately untimed; IAM Fcalc, FFT density, and symmetry-aware Marching Cubes are timed separately. A processor exercise at the beginning and end normalizes drift. The analysis-ready CSV includes asymmetric-unit and expanded unit-cell atom counts, all cell parameters, file size and its empirical quantile, reflection/grid/mesh sizes, raw and normalized timings, predictions, and recommended bounded-preview fractions. Estimates below 300 ms remain one step. Longer calculations may receive up to five 100–200 ms preview redraws, while their combined extra work is capped at 750 ms and 50% of the final estimate. Progress-only signals cover longer gaps without triggering another calculation. Robust log-linear component models and held-out validation errors are written to a JSON sidecar for a later runtime estimator. <code>bench:density-fit</code> regenerates estimates, schedules, and the sidecar from an existing CSV. Directory inputs are stratified into equal-probability intervals of the complete CIF file-size distribution, with one deterministic random selection per interval and shuffled execution order. Partial CSV results are checkpointed every 25 structures.</p><h2 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h2><p>The deployment script is the complete GitHub Pages workflow: it cleans stale output, builds the external-dependency library, the all-dependencies bundle, the playground site, and this documentation, copies them into one self-contained <code>deployment/</code> tree, publishes with <code>gh-pages</code>, and cleans generated output even if publishing fails.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Inspect the assembled tree without publishing:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:deployment</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Remove dist/ and deployment/:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean:deployment</span></span></code></pre></div><h2 id="full-jsdoc" tabindex="-1">Full JSDoc <a class="header-anchor" href="#full-jsdoc" aria-label="Permalink to &quot;Full JSDoc&quot;">​</a></h2><p>Every exported class and function has a JSDoc comment, and <code>eslint-plugin-jsdoc</code> enforces their presence across the codebase, so the generated reference is unusually complete. These pages are the map; JSDoc is the territory — use it when you need the full method/parameter list rather than a narrative explanation.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span></span></code></pre></div><p>Generates a browsable HTML API reference at <code>jsdoc-out/index.html</code>, built from <code>jsdoc.json</code> at the repo root.</p>`,34)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
